import { Link } from "react-router-dom";
import productsData from "../data/ProductData";

const PopularProducts = () => {
  if (!productsData || productsData.length === 0) {
    return <h2 style={{ textAlign: "center" }}>⚠ No products found</h2>;
  }

  const popularItems = productsData.slice(0, 8);

  return (
    <section style={{ padding: "40px" }}>
      {/* Popular Products */}
      <h2 style={{ textAlign: "center", marginBottom: "30px" }}>
        Popular Products
      </h2>

      <div
        style={{
          display: "grid",
          gridTemplateColumns: "repeat(4, 1fr)",
          gap: "25px",
          maxWidth: "1200px",
          margin: "0 auto",
        }}
      >
        {popularItems.map((item) => (
          <div key={item.id} style={{ textAlign: "left" }}>
            {/* Image box */}
            <Link to={'/product/${item.id}'}>
              <div
                style={{
                  border: "1px solid #ddd",
                  padding: "29px",
                  background: "#f1f1f6ff",
                  height: "150px",
                  display: "flex",
                  alignItems: "center",
                  justifyContent: "center",
                }}
              >
                <img
                  src={item.image}
                  alt={item.name}
                  style={{
                    maxWidth: "100%",
                    maxHeight: "180px",
                    objectFit: "contain",
                  }}
                />
              </div>
            </Link>

            {/* Product details */}
            <h3
              style={{
                fontSize: "14px",
                margin: "10px 0 5px",
                fontFamily: "'Poppins', sans-serif",
              }}
            >
              {item.name}
            </h3>
            <p style={{ fontWeight: "bold", margin: "5px 0" }}>₹{item.price}</p>

            {/* ✅ Ratings (stars + number) */}
            <div
              style={{
                display: "flex",
                justifyContent: "left",
                alignItems: "center",
                gap: "5px",
                marginTop: "5px",
              }}
            >
              <span style={{ color: "#ee6b19ff", fontSize: "10px" }}>⭐⭐⭐⭐⭐</span>
              <span style={{ fontSize: "13px", color: "#555" }}>
                {item.rating}
              </span>
            </div>

            <Link to={'/product/${item.id}'}>
              <button
                style={{
                  marginTop: "8px",
                  padding: "8px 15px",
                  border: "none",
                  borderRadius: "6px",
                  background: "#ff6d0cff",
                  color: "#fff",
                  cursor: "pointer",
                }}
              >
                Buy Now
              </button>
            </Link>
          </div>
        ))}
      </div>

      {/* ------------------- Featured Picks Section ------------------- */}
      <section style={{ marginTop: "60px", textAlign: "center" }}>
        <h2 style={{ marginBottom: "20px" }}>✨ Featured Picks</h2>
        <div
          style={{
            display: "grid",
            gridTemplateColumns: "repeat(3, 1fr)",
            gap: "25px",
            maxWidth: "1000px",
            margin: "0 auto",
          }}
        >
          <div style={{ padding: "20px", background: "#f9f9f9", borderRadius: "10px" }}>
            <img
              src="/images/featured1.jpg"
              alt="Featured 1"
              style={{ maxWidth: "100%", borderRadius: "8px" }}
            />
            <h3 style={{ marginTop: "10px" }}>Trending Headphones</h3>
          </div>
          <div style={{ padding: "20px", background: "#f9f9f9", borderRadius: "10px" }}>
            <img
              src="/images/featured2.jpg"
              alt="Featured 2"
              style={{ maxWidth: "100%", borderRadius: "8px" }}
            />
            <h3 style={{ marginTop: "10px" }}>Best Smartphones</h3>
          </div>
          <div style={{ padding: "20px", background: "#f9f9f9", borderRadius: "10px" }}>
            <img
              src="/images/featured3.jpg"
              alt="Featured 3"
              style={{ maxWidth: "100%", borderRadius: "8px" }}
            />
            <h3 style={{ marginTop: "10px" }}>Smart Watches</h3>
          </div>
        </div>
      </section>

      {/* ------------------- Subscribe Section ------------------- */}
      <section
        style={{
          marginTop: "60px",
          padding: "40px",
          background: "#ff6d0cff",
          color: "#fff",
          textAlign: "center",
          borderRadius: "12px",
          maxWidth: "800px",
          marginLeft: "auto",
          marginRight: "auto",
        }}
      >
        <h2 style={{ marginBottom: "20px" }}>📩 Subscribe for Updates</h2>
        <p style={{ marginBottom: "20px" }}>
          Get the latest offers, new arrivals, and exclusive deals straight to your inbox.
        </p>
        <div style={{ display: "flex", justifyContent: "center", gap: "10px" }}>
          <input
            type="email"
            placeholder="Enter your email"
            style={{
              padding: "10px",
              border: "none",
              borderRadius: "6px",
              width: "250px",
            }}
          />
          <button
            style={{
              padding: "10px 20px",
              border: "none",
              borderRadius: "6px",
              background: "#fff",
              color: "#ff6d0cff",
              cursor: "pointer",
              fontWeight: "bold",
            }}
          >
            Subscribe
          </button>
        </div>
      </section>
    </section>
  );
};

export default PopularProducts;
